   361→                                val f = File(pdf.filePath)
   362→                                if (!f.exists()) continue
   363→                                zos.putNextEntry(ZipEntry(pdf.fileName))
   364→                                f.inputStream().use { input ->
   365→                                    val buffer = ByteArray(8192) // 8KB缓冲区
   366→                                    var bytesRead: Int
   367→                                    while (input.read(buffer).also { bytesRead = it } != -1) {
   368→                                        zos.write(buffer, 0, bytesRead)
   369→                                    }
   370→                                }
   371→                                zos.closeEntry()
   372→                            }
   373→                        }
   374→                        zip
   375→                    }
   376→
   377→                    val uri = FileProvider.getUriForFile(ctx, authority, zipFile)
   378→                    val intent = Intent(Intent.ACTION_SEND).apply {
   379→                        type = "application/zip"
   380→                        putExtra(Intent.EXTRA_STREAM, uri)
   381→                        addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION or Intent.FLAG_ACTIVITY_NEW_TASK)
   382→                    }
   383→                    ctx.startActivity(Intent.createChooser(intent, "分享文书").addFlags(Intent.FLAG_ACTIVITY_NEW_TASK))
