package com.court.assistant.viewmodel

import android.app.Application
import android.content.Intent
import androidx.core.content.FileProvider
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.court.assistant.CourtApp
import com.court.assistant.calendar.CalendarSync
import com.court.assistant.data.db.CourtSmsEntity
import com.court.assistant.data.db.PdfDocumentEntity
import com.court.assistant.pdf.PdfDownloadManager
import com.court.assistant.pdf.PdfParser
import com.court.assistant.pdf.DownloadResult
import com.court.assistant.sms.SmsParser
import com.court.assistant.sms.SmsReader
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext
import java.io.File
import java.util.zip.ZipEntry
import java.util.zip.ZipOutputStream

data class SmsWithPdfs(
    val sms: CourtSmsEntity,
    val pdfs: List<PdfDocumentEntity>
)

data class UiState(
    val smsWithPdfs: List<SmsWithPdfs> = emptyList(),
    val loading: Boolean = false,
    val message: String? = null,
    val downloadCount: Int = 0
)

class MainViewModel(application: Application) : AndroidViewModel(application) {
    private val app = application as CourtApp
    private val repo = app.repository
    private val smsReader = SmsReader(application)
    private val smsParser = SmsParser()
    private val calendarSync = CalendarSync(application)
    val pdfDownloader = PdfDownloadManager(application)
    private val pdfParser = PdfParser(application)

    private val _uiState = MutableStateFlow(UiState())
    val uiState: StateFlow<UiState> = _uiState.asStateFlow()

    private val _downloadEvent = MutableSharedFlow<String>()
    val downloadEvent: SharedFlow<String> = _downloadEvent.asSharedFlow()

    init {
        viewModelScope.launch {
            repo.getAllSms().collect { refreshPdfList() }
        }
    }

    private suspend fun refreshPdfList() {
        val smsList = repo.getAllSmsList()
        val withPdfs = smsList.map { sms ->
            val pdfs = repo.getPdfsBySmsId(sms.id).first()
            SmsWithPdfs(sms, pdfs)
        }
        _uiState.update { it.copy(smsWithPdfs = withPdfs, loading = false) }
    }

    fun loadSms() {
        viewModelScope.launch {
            _uiState.update { it.copy(loading = true) }
            val rawList = smsReader.readCourtSms()
            var newCount = 0
            for (raw in rawList) {
                val hash = raw.body.hashCode()
                if (repo.smsExists(hash, raw.sender)) continue
                val parsed = smsParser.parse(raw.body)
                val entity = CourtSmsEntity(
                    sender = raw.sender,
                    body = raw.body,
                    bodyHash = hash,
                    receivedAt = raw.date,
                    caseNumber = parsed.caseNumber,
                    courtName = parsed.courtName,
                    hearingTime = parsed.hearingTime,
                    partyNames = parsed.partyNames,
                    webUrl = parsed.webUrl
                )
                val id = repo.insertSms(entity)
                if (id > 0 && parsed.hearingTime != null && parsed.caseNumber != null) {
                    val eventId = calendarSync.syncHearing(
                        caseNumber = parsed.caseNumber,
                        courtName = parsed.courtName,
                        hearingTime = parsed.hearingTime,
                        defendant = parsed.partyNames,
                        handler = null,
                        location = null,
                        phone = null,
                        partyNames = parsed.partyNames
                    )
                    if (eventId != null) {
                        repo.updateSms(entity.copy(id = id, calendarEventId = eventId))
                    }
                }
                newCount++
            }
            // 重新解析已有短信中未同步日历的记录
            resyncPendingSms()
            _uiState.update { it.copy(loading = false, message = "已读取 ${rawList.size} 条法院短信，新增 $newCount 条") }
        }
    }

    private suspend fun resyncPendingSms() {
        val allSms = repo.getAllSmsList()
        for (sms in allSms) {
            if (sms.calendarEventId != null) continue
            val parsed = smsParser.parse(sms.body)
            // 用新解析器重新解析，更新数据库
            val updated = sms.copy(
                caseNumber = parsed.caseNumber ?: sms.caseNumber,
                courtName = parsed.courtName ?: sms.courtName,
                hearingTime = parsed.hearingTime ?: sms.hearingTime,
                partyNames = parsed.partyNames ?: sms.partyNames,
                webUrl = parsed.webUrl ?: sms.webUrl
            )
            if (parsed.hearingTime != null && parsed.caseNumber != null) {
                val eventId = calendarSync.syncHearing(
                    caseNumber = parsed.caseNumber,
                    courtName = parsed.courtName,
                    hearingTime = parsed.hearingTime,
                    defendant = parsed.partyNames,
                    handler = null,
                    location = null,
                    phone = null,
                    partyNames = parsed.partyNames
                )
                repo.updateSms(updated.copy(calendarEventId = eventId))
            } else if (updated != sms) {
                repo.updateSms(updated)
            }
        }
    }

    fun downloadPdf(url: String, smsId: Long, fileName: String? = null, cookies: String? = null) {
        viewModelScope.launch {
            val result = pdfDownloader.download(url, smsId, fileName, cookies)
            when (result) {
                is DownloadResult.Success -> {
                    // 全局MD5去重：检查是否已存在相同内容的PDF（无论来自哪个短信）
                    val existingPdf = repo.getPdfByMd5(result.fileMd5)
                    if (existingPdf != null) {
                        // 文件已存在，删除刚下载的重复文件
                        File(result.filePath).delete()
                        _downloadEvent.emit("文件已存在: ${result.fileName}（与 ${existingPdf.fileName} 内容相同）")
                        return@launch
                    }

                    val pdf = PdfDocumentEntity(
                        smsId = smsId,
                        fileName = result.fileName,
                        filePath = result.filePath,
                        fileSize = result.fileSize,
                        fileMd5 = result.fileMd5,
                        downloadedAt = System.currentTimeMillis(),
                        isSubpoena = false
                    )
                    // 唯一索引(smsId, fileMd5)保证同一短信下不重复
                    val pdfId = repo.insertPdf(pdf)
                    if (pdfId > 0) {
                        _uiState.update { it.copy(downloadCount = it.downloadCount + 1) }
                        _downloadEvent.emit("已保存: ${result.fileName}")
                        tryParseAndSync(pdfId, result.filePath, smsId)
                        refreshPdfList()
                    } else {
                        File(result.filePath).delete()
                        _downloadEvent.emit("文件已存在: ${result.fileName}")
                    }
                }
                is DownloadResult.Error -> {
                    _downloadEvent.emit("下载失败: ${result.message}")
                }
            }
        }
    }

    private suspend fun tryParseAndSync(pdfId: Long, filePath: String, smsId: Long) {
        val info = pdfParser.parseSubpoena(filePath) ?: return
        val pdf = repo.getPdfById(pdfId) ?: return

        // 判断是否为传票：有开庭时间或文件名/内容含传票关键词
        val isSubpoena = info.hearingTime != null ||
            pdf.fileName.contains("传票") ||
            info.defendant != null

        val hearingDesc = buildString {
            if (info.courtName != null) append("法院: ${info.courtName}\n")
            if (info.defendant != null) append("被传唤人: ${info.defendant}\n")
            if (info.handler != null) append("承办人: ${info.handler}\n")
            if (info.location != null) append("地点: ${info.location}")
            if (info.phone != null) append("\n电话: ${info.phone}")
        }.takeIf { it.isNotBlank() }

        if (info.hearingTime != null && info.caseNumber != null) {
            val eventId = calendarSync.syncHearing(
                caseNumber = info.caseNumber,
                courtName = info.courtName,
                hearingTime = info.hearingTime,
                defendant = info.defendant,
                handler = info.handler,
                location = info.location,
                phone = info.phone,
                caseType = info.caseType
            )
            repo.updatePdf(pdf.copy(isSubpoena = isSubpoena, hearingInfo = hearingDesc, calendarEventId = eventId))
            // 将PDF中解析出的开庭时间回写到SMS
            val sms = repo.getSmsById(smsId)
            if (sms != null && sms.hearingTime == null) {
                repo.updateSms(sms.copy(hearingTime = info.hearingTime))
            }
            if (eventId != null) {
                _downloadEvent.emit("📅 已同步到日历")
            }
        } else if (hearingDesc != null || isSubpoena) {
            repo.updatePdf(pdf.copy(isSubpoena = isSubpoena, hearingInfo = hearingDesc))
        }
    }

    fun resetDownloadCount() {
        _uiState.update { it.copy(downloadCount = 0) }
    }

    fun clearMessage() {
        _uiState.update { it.copy(message = null) }
    }

    fun clearAllData() {
        viewModelScope.launch {
            repo.clearAllData()
            _uiState.update { it.copy(message = "已清除所有数据，可重新同步") }
        }
    }

    fun syncAllToCalendar() {
        viewModelScope.launch {
            _uiState.update { it.copy(loading = true) }
            var synced = 0
            // 同步短信中的开庭信息
            resyncPendingSms()
            // 同步所有PDF
            val allPdfs = repo.getAllPdfs().first()
            for (pdf in allPdfs) {
                if (pdf.calendarEventId != null) continue
                val info = pdfParser.parseSubpoena(pdf.filePath) ?: continue
                if (info.hearingTime == null || info.caseNumber == null) continue
                val eventId = calendarSync.syncHearing(
                    caseNumber = info.caseNumber,
                    courtName = info.courtName,
                    hearingTime = info.hearingTime,
                    defendant = info.defendant,
                    handler = info.handler,
                    location = info.location,
                    phone = info.phone,
                    caseType = info.caseType
                ) ?: continue
                val hearingDesc = buildString {
                    if (info.courtName != null) append("法院: ${info.courtName}\n")
                    if (info.defendant != null) append("被传唤人: ${info.defendant}\n")
                    if (info.handler != null) append("承办人: ${info.handler}\n")
                    if (info.location != null) append("地点: ${info.location}")
                    if (info.phone != null) append("\n电话: ${info.phone}")
                }.takeIf { it.isNotBlank() }
                repo.updatePdf(pdf.copy(isSubpoena = true, hearingInfo = hearingDesc, calendarEventId = eventId))
                synced++
            }
            _uiState.update { it.copy(loading = false, message = if (synced > 0) "已同步 $synced 条日程" else "没有新的日程需要同步") }
        }
    }

    /**
     * 手动同步PDF到日程
     */
    fun syncPdfToCalendar(pdfId: Long) {
        viewModelScope.launch {
            val pdf = repo.getPdfById(pdfId) ?: return@launch
            val info = pdfParser.parseSubpoena(pdf.filePath)

            if (info == null) {
                _uiState.update { it.copy(message = "无法解析文件内容") }
                return@launch
            }

            if (info.hearingTime == null || info.caseNumber == null) {
                _uiState.update { it.copy(message = "未找到开庭时间或案号") }
                return@launch
            }

            val eventId = calendarSync.syncHearing(
                caseNumber = info.caseNumber,
                courtName = info.courtName,
                hearingTime = info.hearingTime,
                defendant = info.defendant,
                handler = info.handler,
                location = info.location,
                phone = info.phone,
                caseType = info.caseType
            )

            if (eventId != null) {
                val hearingDesc = buildString {
                    if (info.courtName != null) append("法院: ${info.courtName}\n")
                    if (info.defendant != null) append("被传唤人: ${info.defendant}\n")
                    if (info.handler != null) append("承办人: ${info.handler}\n")
                    if (info.location != null) append("地点: ${info.location}")
                    if (info.phone != null) append("\n电话: ${info.phone}")
                }.takeIf { it.isNotBlank() }
                repo.updatePdf(pdf.copy(isSubpoena = true, hearingInfo = hearingDesc, calendarEventId = eventId))
                _uiState.update { it.copy(message = "已添加到日历") }
            } else {
                _uiState.update { it.copy(message = "日历事件已存在") }
            }
        }
    }

    fun sharePdfs(pdfIds: List<Long>) {
        viewModelScope.launch {
            try {
                val pdfs = pdfIds.mapNotNull { repo.getPdfById(it) }
                if (pdfs.isEmpty()) {
                    _uiState.update { it.copy(message = "没有可分享的文件") }
                    return@launch
                }

                // 过滤出存在的文件
                val existingPdfs = pdfs.filter { File(it.filePath).exists() }
                if (existingPdfs.isEmpty()) {
                    _uiState.update { it.copy(message = "文件不存在，可能已被删除") }
                    return@launch
                }

                val ctx = getApplication<CourtApp>()
                val authority = "${ctx.packageName}.fileprovider"

                if (existingPdfs.size == 1) {
                    // 单文件分享
                    val file = File(existingPdfs[0].filePath)
                    val uri = FileProvider.getUriForFile(ctx, authority, file)
                    val intent = Intent(Intent.ACTION_SEND).apply {
                        type = "application/pdf"
                        putExtra(Intent.EXTRA_STREAM, uri)
                        addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION or Intent.FLAG_ACTIVITY_NEW_TASK)
                    }
                    ctx.startActivity(Intent.createChooser(intent, "分享文书").addFlags(Intent.FLAG_ACTIVITY_NEW_TASK))
                } else {
                    // 多文件打包为ZIP分享
                    val zipFile = withContext(Dispatchers.IO) {
                        val dir = File(ctx.getExternalFilesDir(null), "Zips")
                        if (!dir.exists()) dir.mkdirs()
                        val zip = File(dir, "法院文书_${System.currentTimeMillis()}.zip")

                        // 使用缓冲区避免内存溢出
                        ZipOutputStream(zip.outputStream()).use { zos ->
                            for (pdf in existingPdfs) {
                                val f = File(pdf.filePath)
                                if (!f.exists()) continue
                                zos.putNextEntry(ZipEntry(pdf.fileName))
                                f.inputStream().use { input ->
                                    val buffer = ByteArray(8192) // 8KB缓冲区
                                    var bytesRead: Int
                                    while (input.read(buffer).also { bytesRead = it } != -1) {
                                        zos.write(buffer, 0, bytesRead)
                                    }
                                }
                                zos.closeEntry()
                            }
                        }
                        zip
                    }

                    val uri = FileProvider.getUriForFile(ctx, authority, zipFile)
                    val intent = Intent(Intent.ACTION_SEND).apply {
                        type = "application/zip"
                        putExtra(Intent.EXTRA_STREAM, uri)
                        addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION or Intent.FLAG_ACTIVITY_NEW_TASK)
                    }
                    ctx.startActivity(Intent.createChooser(intent, "分享文书").addFlags(Intent.FLAG_ACTIVITY_NEW_TASK))
                }
            } catch (e: OutOfMemoryError) {
                _uiState.update { it.copy(message = "内存不足，请尝试分享较少文件") }
            } catch (e: Exception) {
                _uiState.update { it.copy(message = "分享失败: ${e.message}") }
            }
        }
    }
}

package com.court.assistant.pdf

import android.content.Context
import android.graphics.Bitmap
import android.graphics.pdf.PdfRenderer
import android.os.ParcelFileDescriptor
import com.google.mlkit.vision.common.InputImage
import com.google.mlkit.vision.text.TextRecognition
import com.google.mlkit.vision.text.chinese.ChineseTextRecognizerOptions
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.suspendCancellableCoroutine
import kotlinx.coroutines.withContext
import java.io.File
import java.util.*
import kotlin.coroutines.resume

data class SubpoenaInfo(
    val caseNumber: String?,       // 案号
    val courtName: String?,       // 法院简称
    val hearingTime: Long?,       // 应到时间
    val defendant: String?,        // 被传唤人
    val handler: String?,         // 承办人
    val location: String?,        // 应到处所
    val phone: String?,           // 电话
    val caseType: String?         // 案由
)

class PdfParser(private val context: Context) {

    suspend fun parseSubpoena(filePath: String): SubpoenaInfo? = withContext(Dispatchers.IO) {
        val text = extractText(filePath)
        if (text.isNullOrBlank()) return@withContext null
        parseSubpoenaText(text)
    }

    private suspend fun extractText(filePath: String): String? {
        // 先尝试 iText 提取
        val iTextResult = extractWithIText(filePath)
        if (!iTextResult.isNullOrBlank() && iTextResult.any { it.code > 0x4E00 }) {
            return iTextResult
        }
        // 回退到 OCR
        return extractWithOcr(filePath)
    }

    private fun extractWithIText(filePath: String): String? {
        return try {
            val reader = com.itextpdf.kernel.pdf.PdfReader(filePath)
            val doc = com.itextpdf.kernel.pdf.PdfDocument(reader)
            val sb = StringBuilder()
            for (i in 1..doc.numberOfPages) {
                val text = com.itextpdf.kernel.pdf.canvas.parser.PdfTextExtractor.getTextFromPage(doc.getPage(i))
                sb.appendLine(text)
            }
            doc.close()
            sb.toString()
        } catch (_: Exception) { null }
    }

    private suspend fun extractWithOcr(filePath: String): String? {
        val file = File(filePath)
        if (!file.exists()) return null
        val fd = ParcelFileDescriptor.open(file, ParcelFileDescriptor.MODE_READ_ONLY)
        val renderer = PdfRenderer(fd)
        val sb = StringBuilder()
        val recognizer = TextRecognition.getClient(ChineseTextRecognizerOptions.Builder().build())

        for (i in 0 until renderer.pageCount) {
            val page = renderer.openPage(i)
            val bitmap = Bitmap.createBitmap(page.width * 2, page.height * 2, Bitmap.Config.ARGB_8888)
            page.render(bitmap, null, null, PdfRenderer.Page.RENDER_MODE_FOR_DISPLAY)
            page.close()

            val text = suspendCancellableCoroutine<String?> { cont ->
                val image = InputImage.fromBitmap(bitmap, 0)
                recognizer.process(image)
                    .addOnSuccessListener { result -> cont.resume(result.text) }
                    .addOnFailureListener { cont.resume(null) }
            }
            if (text != null) sb.appendLine(text)
            bitmap.recycle()
        }
        renderer.close()
        fd.close()
        return sb.toString().takeIf { it.isNotBlank() }
    }

    private fun parseSubpoenaText(text: String): SubpoenaInfo {
        val caseNumber = Regex("[（(]\\d{4}[）)][^\\s，。]+号").find(text)?.value
        val courtName = Regex("(.+?法院)").find(text)?.groupValues?.get(1)

        // 提取被传唤人（优先提取"被传唤人"或"被告"）
        val defendant = try {
            // 优先匹配"被传唤人"
            Regex("被传唤人[：:]?\\s*([^\\n，。]+)").find(text)?.groupValues?.get(1)?.trim()
                // 其次匹配"被告"
                ?: Regex("被告[：:]?\\s*([^\\n，。]+)").find(text)?.groupValues?.get(1)?.trim()
        } catch (e: Exception) { null }

        // 提取承办人（法官/审判员）
        val handler = try {
            listOf(
                Regex("承办人[：:]?\\s*([^\\n，。]+)"),
                Regex("审判[长员][：:]?\\s*([^\\n，。]+)"),
                Regex("法官[：:]?\\s*([^\\n，。]+)"),
                Regex("经办人[：:]?\\s*([^\\n，。]+)")
            ).firstNotNullOfOrNull { it.find(text)?.groupValues?.get(1)?.trim() }
        } catch (e: Exception) { null }

        // 提取联系电话（手机或固话）
        val phonePattern = "([1][3-9]\\d{9}|0\\d{2,3}-?\\d{7,8})"
        val phone = try {
            listOf(
                Regex("电话[：:]?\\s*$phonePattern"),
                Regex("联系电话[：:]?\\s*$phonePattern"),
                Regex("手机[：:]?\\s*$phonePattern"),
                Regex("联系方式[：:]?\\s*$phonePattern"),
                Regex("(?:tel|Tel|TEL)[：:]?\\s*$phonePattern")
            ).firstNotNullOfOrNull { it.find(text)?.groupValues?.get(1)?.trim() }
        } catch (e: Exception) { null }

        val location = Regex("(?:应到处所|应到地点|地[点址])[：:]?\\s*([^\\n，。]+)").find(text)?.groupValues?.get(1)?.trim()

        var hearingTime: Long? = null
        val timeMatch = Regex("(?:应到时间|开庭时间|定于)[：:]?\\s*(\\d{4})[年-](\\d{1,2})[月-](\\d{1,2})[日号]?[\\s]*(\\d{1,2})[时点:：](\\d{0,2})[分]?").find(text)
        if (timeMatch != null) {
            val hour = timeMatch.groupValues[4].toInt()
            val minute = timeMatch.groupValues[5].takeIf { it.isNotEmpty() }?.toInt() ?: 0
            val cal = Calendar.getInstance(TimeZone.getTimeZone("Asia/Shanghai")).apply {
                clear()
                set(timeMatch.groupValues[1].toInt(),
                    timeMatch.groupValues[2].toInt() - 1,
                    timeMatch.groupValues[3].toInt(),
                    hour, minute, 0)
            }
            hearingTime = cal.timeInMillis
        }

        // 提取案由
        val caseType = Regex("(?:案由|纠纷类型)[：:]?\\s*([^\\n，。]+)").find(text)?.groupValues?.get(1)?.trim()

        return SubpoenaInfo(caseNumber, courtName, hearingTime, defendant, handler, location, phone, caseType)
    }
}

package com.court.assistant.data.db

import android.content.Context
import androidx.room.migration.Migration
import androidx.sqlite.db.SupportSQLiteDatabase
import androidx.room.*

val MIGRATION_1_2 = object : Migration(1, 2) {
    override fun migrate(database: SupportSQLiteDatabase) {
        // 删除旧表并重建，添加 fileMd5 和 ocrTitle 列
        database.execSQL("DROP TABLE IF EXISTS pdf_documents")
        database.execSQL("""
            CREATE TABLE IF NOT EXISTS pdf_documents (
                id INTEGER PRIMARY KEY AUTOINCREMENT NOT NULL,
                smsId INTEGER NOT NULL,
                fileName TEXT NOT NULL,
                filePath TEXT NOT NULL,
                fileSize INTEGER NOT NULL,
                fileMd5 TEXT NOT NULL,
                ocrTitle TEXT,
                downloadedAt INTEGER NOT NULL,
                isSubpoena INTEGER NOT NULL DEFAULT 0,
                hearingInfo TEXT,
                calendarEventId INTEGER,
                FOREIGN KEY(smsId) REFERENCES court_sms(id) ON DELETE CASCADE
            )
        """)
        database.execSQL("CREATE INDEX IF NOT EXISTS index_pdf_documents_smsId ON pdf_documents(smsId)")
        database.execSQL("CREATE UNIQUE INDEX IF NOT EXISTS index_pdf_documents_fileMd5 ON pdf_documents(fileMd5)")
    }
}

val MIGRATION_2_3 = object : Migration(2, 3) {
    override fun migrate(database: SupportSQLiteDatabase) {
        // 重建pdf_documents表，改为 smsId+fileMd5 联合唯一索引
        database.execSQL("DROP TABLE IF EXISTS pdf_documents")
        database.execSQL("""
            CREATE TABLE IF NOT EXISTS pdf_documents (
                id INTEGER PRIMARY KEY AUTOINCREMENT NOT NULL,
                smsId INTEGER NOT NULL,
                fileName TEXT NOT NULL,
                filePath TEXT NOT NULL,
                fileSize INTEGER NOT NULL,
                fileMd5 TEXT NOT NULL,
                ocrTitle TEXT,
                downloadedAt INTEGER NOT NULL,
                isSubpoena INTEGER NOT NULL DEFAULT 0,
                hearingInfo TEXT,
                calendarEventId INTEGER,
                FOREIGN KEY(smsId) REFERENCES court_sms(id) ON DELETE CASCADE
            )
        """)
        database.execSQL("CREATE INDEX IF NOT EXISTS index_pdf_documents_smsId ON pdf_documents(smsId)")
        database.execSQL("CREATE UNIQUE INDEX IF NOT EXISTS index_pdf_documents_smsId_fileMd5 ON pdf_documents(smsId, fileMd5)")
    }
}

val MIGRATION_3_4 = object : Migration(3, 4) {
    override fun migrate(database: SupportSQLiteDatabase) {
        // court_sms唯一索引从bodyHash改为bodyHash+sender，允许不同发送者的相同内容短信共存
        database.execSQL("DROP INDEX IF EXISTS index_court_sms_bodyHash")
        database.execSQL("CREATE UNIQUE INDEX IF NOT EXISTS index_court_sms_bodyHash_sender ON court_sms(bodyHash, sender)")
    }
}

@Database(
    entities = [CourtSmsEntity::class, PdfDocumentEntity::class],
    version = 4,
    exportSchema = false
)
abstract class CourtDatabase : RoomDatabase() {
    abstract fun courtDao(): CourtDao

    companion object {
        @Volatile
        private var INSTANCE: CourtDatabase? = null

        fun getInstance(context: Context): CourtDatabase {
            return INSTANCE ?: synchronized(this) {
                Room.databaseBuilder(
                    context.applicationContext,
                    CourtDatabase::class.java,
                    "court_assistant.db"
                )
                .addMigrations(MIGRATION_1_2, MIGRATION_2_3, MIGRATION_3_4)
                .build().also { INSTANCE = it }
            }
        }
    }
}

