                    caseNumber = caseNumber,
                    fileName = finalFileName,
                    filePath = finalPath,
                    fileSize = result.fileSize,
                    fileMd5 = result.fileMd5,
                    downloadedAt = System.currentTimeMillis(),
                    isSubpoena = pdfInfo?.hearingTime != null
                )
                try {
                    val pdfId = repo.insertPdf(pdf)
                    if (pdfId > 0) {
                        _uiState.update { it.copy(downloadCount = it.downloadCount + 1) }
                        _downloadEvent.emit("已保存: $finalFileName${caseNumber?.let { " [$it]" } ?: ""}")
                        // 如果解析到了开庭信息，同步到日历
                        if (pdfInfo != null && pdfInfo.hearingTime != null && pdfInfo.caseNumber != null) {
                            trySyncPdfToCalendar(pdfId, pdf, pdfInfo)
                        }
                        refreshPdfList()
                    } else {
                        File(finalPath).delete()
                        _downloadEvent.emit("保存失败: $finalFileName")
                    }
                } catch (e: Exception) {
                    android.util.Log.e("CourtAssistant", "保存PDF失败", e)
                    File(finalPath).delete()
                    _downloadEvent.emit("保存失败: $finalFileName")
                }
            }
            is DownloadResult.Error -> {
                _downloadEvent.emit("下载失败: ${result.message}")
            }
        }
    }
}

/**
 * 生成唯一文件名：如果同名文件已存在，添加序号后缀
 */
private suspend fun makeUniqueFileName(originalName: String, smsId: Long): String {
    val existingPdfs = repo.getPdfsBySmsId(smsId).first()
    val existingNames = existingPdfs.map { it.fileName }.toSet()

    if (originalName !in existingNames) {
        return originalName
    }

    val baseName = originalName.substringBeforeLast(".")
    val ext = originalName.substringAfterLast(".", "pdf")
    var suffix = 1
    while ("${baseName}_$suffix.$ext" in existingNames) {
        suffix++
    }
    return "${baseName}_$suffix.$ext"
}

